/**
 * 03-load-management.spec.ts
  *
   * SUITE: Load Management (Admin)
    *
     * Tests:
      *   1. Create a load — POST /api/loads with full fields
       *   2. List loads — GET /api/loads returns the created load
        *   3. Update load — PUT /api/loads/:id changes status
         *   4. Assign driver — PUT /api/loads/:id sets driver_id
          *   5. Update load status through full lifecycle: booked > dispatched > in_transit > delivered
           *   6. Validate load fields — rate, origin, destination are required
            *   7. Cannot access other company loads — returns empty or 401
             *   8. Delete load — DELETE /api/loads/:id
              */

              import { test, expect } from '@playwright/test';
              import { loadContext, saveContext } from './helpers';

              test.describe('Load Management', () => {

                test('01 - POST /api/loads creates a new load', async ({ request }) => {
                    const ctx = loadContext();
                        const loadNum = 'HF-' + Date.now().toString().slice(-6);

                            const res = await request.post(ctx.baseUrl + '/api/loads', {
                                  headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                        data: {
                                                load_number: loadNum,
                                                        shipper_id: ctx.shipperId,
                                                                customer_id: ctx.customerId,
                                                                        driver_id: ctx.driverId,
                                                                                origin_address: '200 Warehouse Row',
                                                                                        origin_city: 'Detroit',
                                                                                                origin_state: 'MI',
                                                                                                        origin_zip: '48201',
                                                                                                                destination_address: '555 Industrial Way',
                                                                                                                        destination_city: 'Chicago',
                                                                                                                                destination_state: 'IL',
                                                                                                                                        destination_zip: '60601',
                                                                                                                                                pickup_date: '2026-07-10',
                                                                                                                                                        delivery_date: '2026-07-11',
                                                                                                                                                                rate: 2850.00,
                                                                                                                                                                        status: 'booked',
                                                                                                                                                                                weight: 42000,
                                                                                                                                                                                        commodity: 'Steel coils',
                                                                                                                                                                                                notes: 'Fragile — strap carefully',
                                                                                                                                                                                                      },
                                                                                                                                                                                                          });
                                                                                                                                                                                                          
                                                                                                                                                                                                              expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                  const body = await res.json();
                                                                                                                                                                                                                      expect(body.id).toBeTruthy();
                                                                                                                                                                                                                          expect(body.load_number).toBe(loadNum);
                                                                                                                                                                                                                              expect(parseFloat(body.rate)).toBe(2850);
                                                                                                                                                                                                                                  expect(body.status).toBe('booked');
                                                                                                                                                                                                                                      saveContext({ loadId: body.id });
                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                          test('02 - GET /api/loads returns loads list including created load', async ({ request }) => {
                                                                                                                                                                                                                                              const ctx = loadContext();
                                                                                                                                                                                                                                                  const res = await request.get(ctx.baseUrl + '/api/loads', {
                                                                                                                                                                                                                                                        headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                    const body = await res.json();
                                                                                                                                                                                                                                                                        expect(Array.isArray(body)).toBeTruthy();
                                                                                                                                                                                                                                                                            const load = body.find((l) => l.id === ctx.loadId);
                                                                                                                                                                                                                                                                                expect(load).toBeTruthy();
                                                                                                                                                                                                                                                                                    expect(load.driver_name).toBe('Bobby Roadhog');
                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                        test('03 - PUT /api/loads/:id updates load to dispatched', async ({ request }) => {
                                                                                                                                                                                                                                                                                            const ctx = loadContext();
                                                                                                                                                                                                                                                                                                const res = await request.put(ctx.baseUrl + '/api/loads/' + ctx.loadId, {
                                                                                                                                                                                                                                                                                                      headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                            data: {
                                                                                                                                                                                                                                                                                                                    load_number: 'HF-UPDATED',
                                                                                                                                                                                                                                                                                                                            origin_address: '200 Warehouse Row',
                                                                                                                                                                                                                                                                                                                                    origin_city: 'Detroit',
                                                                                                                                                                                                                                                                                                                                            origin_state: 'MI',
                                                                                                                                                                                                                                                                                                                                                    origin_zip: '48201',
                                                                                                                                                                                                                                                                                                                                                            destination_address: '555 Industrial Way',
                                                                                                                                                                                                                                                                                                                                                                    destination_city: 'Chicago',
                                                                                                                                                                                                                                                                                                                                                                            destination_state: 'IL',
                                                                                                                                                                                                                                                                                                                                                                                    destination_zip: '60601',
                                                                                                                                                                                                                                                                                                                                                                                            rate: 2850.00,
                                                                                                                                                                                                                                                                                                                                                                                                    status: 'dispatched',
                                                                                                                                                                                                                                                                                                                                                                                                            driver_id: ctx.driverId,
                                                                                                                                                                                                                                                                                                                                                                                                                    customer_id: ctx.customerId,
                                                                                                                                                                                                                                                                                                                                                                                                                            shipper_id: ctx.shipperId,
                                                                                                                                                                                                                                                                                                                                                                                                                                  },
                                                                                                                                                                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                                                                                                                                                                          expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                              const body = await res.json();
                                                                                                                                                                                                                                                                                                                                                                                                                                                  expect(body.status).toBe('dispatched');
                                                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                      test('04 - Load lifecycle: booked -> dispatched -> in_transit -> delivered', async ({ request }) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                          const ctx = loadContext();
                                                                                                                                                                                                                                                                                                                                                                                                                                                              const statuses = ['in_transit', 'delivered'];
                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  for (const status of statuses) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const res = await request.put(ctx.baseUrl + '/api/loads/' + ctx.loadId, {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        data: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  load_number: 'HF-UPDATED',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            origin_address: '200 Warehouse Row',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      origin_city: 'Detroit',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                origin_state: 'MI',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          origin_zip: '48201',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    destination_address: '555 Industrial Way',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              destination_city: 'Chicago',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        destination_state: 'IL',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  destination_zip: '60601',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            rate: 2850.00,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      status: status,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                driver_id: ctx.driverId,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          customer_id: ctx.customerId,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    shipper_id: ctx.shipperId,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        expect(res.ok(), 'Failed to set status: ' + status).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const body = await res.json();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    expect(body.status).toBe(status);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            test('05 - Create a second load for invoicing tests', async ({ request }) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const ctx = loadContext();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const res = await request.post(ctx.baseUrl + '/api/loads', {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                data: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        load_number: 'HF-INV-TEST',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                shipper_id: ctx.shipperId,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        customer_id: ctx.customerId,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                driver_id: ctx.driverId,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        origin_address: '100 Origin St',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                origin_city: 'Memphis',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        origin_state: 'TN',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                origin_zip: '38101',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        destination_address: '200 Destination Ave',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                destination_city: 'Atlanta',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        destination_state: 'GA',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                destination_zip: '30301',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        pickup_date: '2026-07-15',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                delivery_date: '2026-07-16',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        rate: 1950.00,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                status: 'delivered',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        weight: 38000,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                commodity: 'Auto parts',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  test('06 - GET /api/drivers returns driver list', async ({ request }) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const ctx = loadContext();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const res = await request.get(ctx.baseUrl + '/api/drivers', {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const body = await res.json();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                expect(Array.isArray(body)).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const driver = body.find((d) => d.id === ctx.driverId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        expect(driver).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            expect(driver.name).toBe('Bobby Roadhog');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                expect(driver.status).toBe('available');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    test('07 - GET /api/trucks returns truck list', async ({ request }) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const ctx = loadContext();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const res = await request.get(ctx.baseUrl + '/api/trucks', {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const body = await res.json();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  expect(Array.isArray(body)).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      expect(body.some((t) => t.unit_number === 'T-101')).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          test('08 - GET /api/customers returns customer list', async ({ request }) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const ctx = loadContext();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const res = await request.get(ctx.baseUrl + '/api/customers', {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const body = await res.json();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        expect(body.some((c) => c.id === ctx.customerId)).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            test('09 - GET /api/shippers returns shipper list', async ({ request }) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const ctx = loadContext();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const res = await request.get(ctx.baseUrl + '/api/shippers', {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const body = await res.json();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          expect(body.some((s) => s.id === ctx.shipperId)).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
